mapper.select:
SELECT COALESCE(MAX(FILE_SEQ), 0) + 1
FROM EDMS_FILE_MNG
WHERE FILE_ID = #{fileId}

mapper.insert:
INSERT INTO EDMS_FILE_MNG (
FILE_ID, FILE_SEQ, ORG_FILE_NAME, SAVE_FILE_NAME, FILE_PATH, FILE_SIZE, FILE_EXT
) VALUES (
#{fileId}, #{fileSeq}, #{orgFileName}, #{saveFileName}, #{filePath}, #{fileSize}, #{fileExt}
)
